import { useRef, useState } from 'react'
import { Link } from 'react-router-dom'
import { useDispatch, useSelector } from 'react-redux'
import {
  Paper,
  Box,
  Typography,
  TextField,
  CircularProgress,
  Alert,
  Button
} from '@mui/material'
import { register } from '../redux/apiCalls'
import * as styles from '../styles/Login.styles'

const Login = () => {
  const dispatch = useDispatch()
  const fullName = useRef()
  const email = useRef()
  const password = useRef()
  const confirmPassword = useRef()
  const [passwordMatchError, setPasswordMatchError] = useState(false)

  const { loading } = useSelector(state => state.user)

  const handleSubmit = async (e) => {
    e.preventDefault()

    try {
      if (password.current.value !== confirmPassword.current.value) {
        setPasswordMatchError(true)
        return
      }

      register(dispatch, {
        fullName: fullName.current.value,
        email: email.current.value,
        password: password.current.value
      })
    } catch (err) {
      console.error(err)
    }
  }

  return (
    <Box sx={styles.container}>
      <Paper sx={styles.wrapper}>
        <Typography
          variant='h5'
          sx={{textAlign: 'center'}}
        >
          Sign Up
        </Typography>

        <form onSubmit={handleSubmit}>
          <Typography>Full Name</Typography>
          <TextField
            placeholder='Enter Full Name'
            variant='outlined'
            margin='dense'
            inputRef={fullName}
            fullWidth
            required
            autoFocus
          />

          <Typography sx={{mt: 1}}>Email</Typography>
          <TextField
            type='email'
            placeholder='Enter Email'
            variant='outlined'
            margin='dense'
            inputRef={email}
            fullWidth
            required
          />

          <Typography sx={{mt: 1}}>Password</Typography>
          <TextField
            type='password'
            placeholder='Enter password'
            variant='outlined'
            margin='dense'
            inputRef={password}
            fullWidth
            required
          />

          <Typography sx={{mt: 1}}>Confirm Password</Typography>
          <TextField
            type='password'
            placeholder='Confirm password'
            variant='outlined'
            margin='dense'
            inputRef={confirmPassword}
            fullWidth
            required
          />
          {passwordMatchError && <Alert severity='error' sx={{mt:3}}>Passwords do not match</Alert>}
          {loading && (
            <Box sx={{
              mt: 3,
              display: 'flex',
              justifyContent: 'center'
            }}>
              <CircularProgress />
            </Box>
          )}
          <Typography sx={{mt: 3}}>
            Already have an account? <Link to='/'>Login</Link>
          </Typography>
          <Button type='submit' variant='contained' fullWidth sx={{mt: 3}}>Submit</Button>
        </form>
      </Paper>
    </Box>
  )
}

export default Login
